import { db } from './firebase';
import { doc, getDoc } from 'firebase/firestore';

async function getApiKey() {
  const snap = await getDoc(doc(db, 'settings', 'apiKeys'));
  return snap.exists() ? (snap.data().anthropicKey || '') : '';
}

// Extract the first complete, valid JSON value (object or array) from a text blob,
// even if the model added extra commentary before/after it.
function extractJSON(text) {
  let start = -1;
  for (let i = 0; i < text.length; i++) {
    if (text[i] === '{' || text[i] === '[') { start = i; break; }
  }
  if (start === -1) throw new Error('No JSON in response');
  const openCh = text[start];
  const closeCh = openCh === '{' ? '}' : ']';
  let depth = 0;
  let inString = false;
  let escape = false;
  for (let i = start; i < text.length; i++) {
    const ch = text[i];
    if (inString) {
      if (escape) {
        escape = false;
      } else if (ch === '\\') {
        escape = true;
      } else if (ch === '"') {
        inString = false;
      }
      continue;
    }
    if (ch === '"') { inString = true; continue; }
    if (ch === openCh) depth++;
    else if (ch === closeCh) {
      depth--;
      if (depth === 0) {
        const candidate = text.slice(start, i + 1);
        return JSON.parse(candidate);
      }
    }
  }
  throw new Error('No complete JSON value found in response');
}

async function callClaude(prompt, useWebSearch = true) {
  const apiKey = await getApiKey();
  if (!apiKey) throw new Error('No Anthropic API key configured. Go to Settings to add one.');
  const body = {
    model: 'claude-sonnet-4-6',
    max_tokens: 1500,
    messages: [{ role: 'user', content: prompt }]
  };
  if (useWebSearch) {
    body.tools = [{ type: 'web_search_20250305', name: 'web_search' }];
  }
  const response = await fetch('https://api.anthropic.com/v1/messages', {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'x-api-key': apiKey,
      'anthropic-version': '2023-06-01',
      'anthropic-dangerous-direct-browser-access': 'true'
    },
    body: JSON.stringify(body)
  });
  const data = await response.json();
  if (data.error) throw new Error(data.error.message || 'API error');
  const textBlocks = data.content?.filter(b => b.type === 'text').map(b => b.text) || [];
  const text = textBlocks.join('\n');
  return extractJSON(text);
}

// Search the web for a provider (hotel, transport, guide, etc.)
export async function aiFillProvider(name) {
  const prompt = `Search the web for this travel industry provider/company and return ONLY a valid JSON object, absolutely no markdown, no explanation, no code blocks - just the raw JSON on its own. Fields: name (string), type (one of: hotel/transport/guide/attraction/restaurant/other), address (street address), city, zip, country, vat (VAT/DIC tax number if found), ico (company registration number/ICO if found), email (reservations/groups email if found), phone, website, notes (brief useful notes for a tour operator, e.g. group booking conditions). Provider to search: "${name}". Use empty string "" for fields you cannot find.`;
  return callClaude(prompt, true);
}

// Search the web for a Brazilian/international tour operator client
export async function aiFillClient(name) {
  const prompt = `Search the web for this tour operator / travel agency company and return ONLY a valid JSON object, absolutely no markdown, no explanation, no code blocks - just the raw JSON on its own. Fields: name (string, official company name), country (string), state (string, state/province/federation unit if applicable e.g. for Brazil "Estado" like "SP", "RJ"), billingCompany (full legal company name), billingAddress (street address), billingCity, billingZip, billingCountry, billingVat (VAT/CNPJ/tax number if found), billingIco (company registration number if different from VAT), billingEmail (contact/info email if found), website, notes (brief useful info). Company to search: "${name}". Use empty string "" for fields you cannot find.`;
  return callClaude(prompt, true);
}

// Parse pasted free-text into structured provider fields (no web search, just extraction)
export async function parseProviderText(text) {
  const prompt = `Extract structured company/provider information from the following text. Return ONLY a valid JSON object, absolutely no markdown, no explanation, no code blocks - just the raw JSON. Fields: name, type (one of: hotel/transport/guide/attraction/restaurant/other - guess based on context), address (street), city, zip, country, vat (VAT/DIC/tax number), ico (company registration number/ICO), email, phone, website, notes (any other relevant info not captured above). Use empty string "" for fields not present in the text.\n\nTEXT TO PARSE:\n${text}`;
  return callClaude(prompt, false);
}

// Parse pasted free-text into structured client (tour operator) fields
export async function parseClientText(text) {
  const prompt = `Extract structured company information from the following text about a tour operator / travel agency. Return ONLY a valid JSON object, absolutely no markdown, no explanation, no code blocks - just the raw JSON. Fields: name (agency/brand name), country, state (state/province/federation unit, e.g. for Brazil "SP", "RJ"), billingCompany (full legal company name), billingAddress (street), billingCity, billingZip, billingCountry, billingVat (VAT/CNPJ/tax number), billingIco (registration number if different), billingEmail, notes (any other relevant info), contacts (array of objects with name, role, email, phone - extract any people mentioned). Use empty string "" or empty array for fields not present in the text.\n\nTEXT TO PARSE:\n${text}`;
  return callClaude(prompt, false);
}

async function getGeminiKey() {
  const snap = await getDoc(doc(db, 'settings', 'apiKeys'));
  return snap.exists() ? (snap.data().geminiKey || '') : '';
}

async function callGemini(prompt) {
  const GEMINI_KEY = await getGeminiKey();
  if (!GEMINI_KEY) throw new Error('No Gemini API key configured. Go to Settings to add one.');
  const response = await fetch(
    `https://generativelanguage.googleapis.com/v1beta/models/gemini-2.0-flash:generateContent?key=${GEMINI_KEY}`,
    {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        contents: [{ parts: [{ text: prompt }] }],
        tools: [{ google_search: {} }],
        generationConfig: { temperature: 0.1, maxOutputTokens: 1500 }
      })
    }
  );
  const data = await response.json();
  if (data.error) throw new Error(data.error.message || 'Gemini API error');
  const text = data.candidates?.[0]?.content?.parts?.map(p => p.text || '').join('') || '';
  return extractJSON(text);
}

// Search the web (free, via Gemini) for a provider (hotel, transport, guide, etc.)
export async function aiFillProviderFree(name) {
  const prompt = `Search the web for this travel industry provider/company and return ONLY a valid JSON object, absolutely no markdown, no explanation, no code blocks - just the raw JSON on its own. Fields: name (string), type (one of: hotel/transport/guide/attraction/restaurant/other), address (street address), city, zip, country, vat (VAT/DIC tax number if found), ico (company registration number/ICO if found), email (reservations/groups email if found), phone, website, notes (brief useful notes for a tour operator, e.g. group booking conditions). Provider to search: "${name}". Use empty string "" for fields you cannot find.`;
  try {
    return await callGemini(prompt);
  } catch (err) {
    console.warn('Gemini lookup failed, falling back to Claude web search:', err.message);
    return aiFillProvider(name);
  }
}

// Search the web (free, via Gemini) for a Brazilian/international tour operator client
export async function aiFillClientFree(name) {
  const prompt = `Search the web for this tour operator / travel agency company and return ONLY a valid JSON object, absolutely no markdown, no explanation, no code blocks - just the raw JSON on its own. Fields: name (string, official company name), country (string), state (string, state/province/federation unit if applicable e.g. for Brazil "Estado" like "SP", "RJ"), billingCompany (full legal company name), billingAddress (street address), billingCity, billingZip, billingCountry, billingVat (VAT/CNPJ/tax number if found), billingIco (company registration number if different from VAT), billingEmail (contact/info email if found), website, notes (brief useful info). Company to search: "${name}". Use empty string "" for fields you cannot find.`;
  try {
    return await callGemini(prompt);
  } catch (err) {
    console.warn('Gemini lookup failed, falling back to Claude web search:', err.message);
    return aiFillClient(name);
  }
}

const SERVICE_FIELD_HINTS = {
  hotel: `name (hotel name), city, dateFrom (YYYY-MM-DD, check-in date), dateTo (YYYY-MM-DD, check-out date), nights (number of nights),
email (the hotel/sales contact's email address if mentioned anywhere in the text, e.g. in a signature - look carefully for any @ address),
phone (the hotel/sales contact's phone number if mentioned anywhere in the text),
website (the hotel's website URL if mentioned anywhere in the text),
dblRooms (number of double rooms), pricePerDblRoom (price per DBL room per night, number only),
snglRooms (number of single rooms), pricePerSnglRoom (price per SNGL room per night, number only),
twnRooms (number of twin rooms), pricePerTwnRoom (price per TWN room per night, number only),
trplRooms (number of triple rooms), pricePerTrplRoom (price per TRPL room per night, number only),
currency (3-letter code, e.g. EUR/NOK/DKK/CZK/GBP/CHF/PLN/USD),
cityTax (city tax amount, number only),
cityTaxIncluded ("included" if the text says city tax is included in the room price, otherwise "separate"),
cityTaxType ("per_person" if charged per person per night, "per_room" if per room per night, "percent" if a percentage of room price - default "per_person" if unclear),
dinners (number of dinner nights included), dinnerPrice (price per person for dinner),
lunches (number of lunch days included), lunchPrice (price per person for lunch),
hotelFoc (free-of-charge policy as "1 per X" e.g. "1 per 20" if the text mentions e.g. "1 free place per 20 paying", otherwise "none"),
hotelFocOccupancy ("sngl"/"dbl"/"twn"/"trpl" - what room type the free person occupies, default "dbl" if unclear),
cancellationDays (number of days before arrival for free cancellation, if stated as "X days before arrival"),
cancellationDate (YYYY-MM-DD, if a specific cancellation deadline date is given instead of a day count),
notes (any other important conditions, payment terms, deposit requirements, etc., in 1-2 sentences)`,
  restaurant: 'name (restaurant name), city, dateFrom (YYYY-MM-DD), totalPrice (sum of all amounts/prices mentioned in the text, as a single number, if multiple amounts add them all up), currency (3-letter code, e.g. EUR/GBP/CZK/USD/NOK/DKK/CHF/PLN), notes (brief summary of what is included, in 1-2 sentences)',
  ticket: 'name (attraction/ticket name), city',
  train_boat: 'name, city, dateFrom (YYYY-MM-DD, earliest date mentioned), dateTo (YYYY-MM-DD, latest date mentioned), totalPrice (sum of all amounts/prices mentioned in the text, as a single number, if multiple amounts add them all up), currency (3-letter code, e.g. EUR/GBP/CZK/USD/NOK/DKK/CHF/PLN), notes (brief summary of what is included, in 1-2 sentences)',
  bus: 'name (transport company), city, dateFrom (YYYY-MM-DD, earliest date mentioned in the itinerary/text), dateTo (YYYY-MM-DD, latest date mentioned in the itinerary/text), totalPrice (sum of ALL amounts/prices mentioned anywhere in the text for transfers/transport/tours, as a single number - add up every individual price found, even if there are many separate line items), currency (3-letter code, e.g. EUR/GBP/CZK/USD/NOK/DKK/CHF/PLN), notes (brief 2-3 sentence summary listing each day/leg and its price, so the user can verify the total)',
  guide: 'name, city, dateFrom (YYYY-MM-DD, earliest date mentioned), dateTo (YYYY-MM-DD, latest date mentioned), totalPrice (sum of all amounts/prices mentioned in the text, as a single number, if multiple amounts add them all up), currency (3-letter code, e.g. EUR/GBP/CZK/USD/NOK/DKK/CHF/PLN), notes (brief summary, in 1-2 sentences)',
  extra_cost: 'name, city, dateFrom (YYYY-MM-DD if a date is mentioned), totalPrice (sum of all amounts/prices mentioned in the text, as a single number, if multiple amounts add them all up), currency (3-letter code, e.g. EUR/GBP/CZK/USD/NOK/DKK/CHF/PLN), notes (brief summary, in 1-2 sentences)',
  other: 'name, city, dateFrom (YYYY-MM-DD, earliest date mentioned), dateTo (YYYY-MM-DD, latest date mentioned), totalPrice (sum of all amounts/prices mentioned in the text, as a single number, if multiple amounts add them all up), currency (3-letter code, e.g. EUR/GBP/CZK/USD/NOK/DKK/CHF/PLN), notes (brief summary listing each item and its price, in 1-2 sentences)',
};

// Parse pasted text (e.g. from a client email) into service fields for a specific order service type
export async function parseServiceText(text, serviceType) {
  const hints = SERVICE_FIELD_HINTS[serviceType] || SERVICE_FIELD_HINTS.other;
  const multiNote = serviceType === 'hotel'
    ? ' If the text describes rates/details for MULTIPLE DIFFERENT hotels (e.g. a quote comparing several properties), return a JSON ARRAY where each element is an object with the fields below for that hotel. If only ONE hotel is described, return a single JSON object (not wrapped in an array).'
    : '';
  const prompt = `Extract booking information from the following text (likely from an email, possibly in Portuguese, about a European tour booking). Return ONLY valid JSON, absolutely no markdown, no explanation, no code blocks - just the raw JSON.${multiNote} Today's reference year context: if a date has no year, assume the year mentioned elsewhere in the text or 2027 if none given. Fields to extract: ${hints}. Use empty string "" for fields not present in the text. Dates must be in YYYY-MM-DD format.\n\nTEXT:\n${text}`;
  return callClaude(prompt, false);
}

async function callClaudeWithDocument(prompt, base64Data, mediaType) {
  const apiKey = await getApiKey();
  if (!apiKey) throw new Error('No Anthropic API key configured. Go to Settings to add one.');
  const body = {
    model: 'claude-sonnet-4-6',
    max_tokens: 1500,
    messages: [{
      role: 'user',
      content: [
        { type: 'document', source: { type: 'base64', media_type: mediaType, data: base64Data } },
        { type: 'text', text: prompt }
      ]
    }]
  };
  const response = await fetch('https://api.anthropic.com/v1/messages', {
    method: 'POST',
    headers: {
      'Content-Type': 'application/json',
      'x-api-key': apiKey,
      'anthropic-version': '2023-06-01',
      'anthropic-dangerous-direct-browser-access': 'true'
    },
    body: JSON.stringify(body)
  });
  const data = await response.json();
  if (data.error) throw new Error(data.error.message || 'API error');
  const textBlocks = data.content?.filter(b => b.type === 'text').map(b => b.text) || [];
  const text = textBlocks.join('\n');
  return extractJSON(text);
}

// Parse an uploaded PDF contract/confirmation into service fields
export async function parseServiceDocument(base64Data, mediaType, serviceType) {
  const hints = SERVICE_FIELD_HINTS[serviceType] || SERVICE_FIELD_HINTS.other;
  const multiNote = serviceType === 'hotel'
    ? ' If the document describes rates/details for MULTIPLE DIFFERENT hotels (e.g. a quote comparing several properties), return a JSON ARRAY where each element is an object with the fields below for that hotel. If only ONE hotel is described, return a single JSON object (not wrapped in an array).'
    : '';
  const prompt = `This document is a hotel/service contract or confirmation, possibly in Portuguese, Czech, English or another European language, related to a European tour booking. Extract booking information and return ONLY valid JSON, absolutely no markdown, no explanation, no code blocks - just the raw JSON.${multiNote} Today's reference year context: if a date has no year, assume the year mentioned elsewhere in the document or 2027 if none given. Fields to extract: ${hints}. Use empty string "" for fields not present in the document. Dates must be in YYYY-MM-DD format.`;
  return callClaudeWithDocument(prompt, base64Data, mediaType);
}
